import { Box, List, ListItemButton, ListItemText } from "@mui/material";
import { useNavigate, useLocation } from "react-router-dom";

export default function Sidebar() {
  const navigate = useNavigate();
  const location = useLocation();

  // 🔥 GET ROLE FROM LOCALSTORAGE
  const role = localStorage.getItem("role");

  return (
    <Box
      sx={{
        width: 220,
        height: "100vh",
        background: "#1e2a38",
        color: "#fff",
        position: "fixed",
        left: 0,
        top: 0,
        pt: 10,
      }}
    >
      <List>
        {/* 👑 SUPERADMIN MENU */}
        {role === "superadmin" && (
          <>
            <ListItemButton
              selected={location.pathname === "/superadmin"}
              onClick={() => {
                if (location.pathname !== "/superadmin") {
                  navigate("/superadmin");
                }
              }}
            >
              <ListItemText primary="Create Organization" />
            </ListItemButton>

            <ListItemButton
              selected={location.pathname === "/organizations"}
              onClick={() => {
                if (location.pathname !== "/organizations") {
                  navigate("/organizations");
                }
              }}
            >
              <ListItemText primary="Organization Management" />
            </ListItemButton>
          </>
        )}

        {/* 🏢 ADMIN MENU */}
        {role === "admin" && (
          <>
            <ListItemButton
              selected={location.pathname === "/admin/projects"}
              onClick={() => {
                if (location.pathname !== "/admin/projects") {
                  navigate("/admin/projects");
                }
              }}
            >
              <ListItemText primary="Project Setup" />
            </ListItemButton>

            <ListItemButton
              selected={location.pathname === "/admin/project-management"}
              onClick={() => {
                if (location.pathname !== "/admin/project-management") {
                  navigate("/admin/project-management");
                }
              }}
            >
              <ListItemText primary="Project Management" />
            </ListItemButton>
          </>
        )}
      </List>
    </Box>
  );
}
